import{_ as a,c as m,o as e,b as t}from"./app.81e64653.js";const k='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 20","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 20","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 3.","tags":"vim-3","date":"2021-01-30T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/3/20/index.md"}',r={},u=t('<div class="stanza"><a href="#s3.20" id="s3.20" class="num">3.20</a><div class="sans"><p>\u092F\u0924 \u090F\u0935\u092E\u0924\u0903 \u0936\u0941\u0926\u094D\u0927\u0935\u093F\u0926\u094D\u092F\u093E\u0938\u094D\u0935\u0930\u0942\u092A\u092E\u0941\u0915\u094D\u0924\u092F\u0941\u0915\u094D\u0924\u093F\u092D\u093F\u0930\u093E\u0938\u093E\u0926\u093F\u0924\u092E\u092A\u093F \u092F\u0925\u093E \u0928 \u0928\u0936\u094D\u092F\u0924\u093F \u0924\u0925\u093E \u0938\u0930\u094D\u0935\u0926\u0936\u093E\u0938\u0941 \u092F\u094B\u0917\u093F\u0928\u093E \u0938\u093E\u0935\u0927\u093E\u0928\u0947\u0928 \u092D\u0935\u093F\u0924\u0935\u094D\u092F\u092E\u093F\u0924\u094D\u092F\u093E\u0939\u2014</p><blockquote><p><strong>\u0924\u094D\u0930\u093F\u0937\u0941 \u091A\u0924\u0941\u0930\u094D\u0925\u0902 \u0924\u0948\u0932\u0935\u0926\u093E\u0938\u0947\u091A\u094D\u092F\u092E\u094D\u0965\u0968\u0966\u0965</strong></p></blockquote><p>\u0924\u094D\u0930\u093F\u0937\u0941 \u091C\u093E\u0917\u0930\u093E\u0926\u093F\u0937\u0941 \u092A\u0926\u0947\u0937\u0941 \u091A\u0924\u0941\u0930\u094D\u0925\u0902 \u0936\u0941\u0926\u094D\u0927\u0935\u093F\u0926\u094D\u092F\u093E\u092A\u094D\u0930\u0915\u093E\u0936\u0930\u0942\u092A\u0902 \u0924\u0941\u0930\u094D\u092F\u093E\u0928\u0928\u094D\u0926\u0930\u0938\u093E\u0924\u094D\u092E\u0915\u0902 \u0927\u093E\u092E \u0924\u0948\u0932\u0935\u0926\u093F\u0924\u093F \u092F\u0925\u093E \u0924\u0948\u0932\u0902 \u0915\u094D\u0930\u092E\u0947\u0923\u093E\u0927\u093F\u0915\u092E\u0927\u093F\u0915\u0902 \u092A\u094D\u0930\u0938\u0930\u0926\u093E\u0936\u094D\u0930\u092F\u0902 \u0935\u094D\u092F\u093E\u092A\u094D\u0928\u094B\u0924\u093F \u0924\u0925\u093E\u0938\u0947\u091A\u094D\u092F\u092E\u094D\u0964 \u0924\u094D\u0930\u093F\u0937\u094D\u0935\u092A\u093F \u092A\u0926\u0947\u0937\u0942\u0928\u094D\u092E\u0947\u0937\u094B\u092A\u0936\u093E\u0928\u094D\u0924\u094D\u092F\u093E\u0924\u094D\u092E\u0915\u093E\u0926\u094D\u092F\u0928\u094D\u0924\u0915\u094B\u091F\u094D\u092F\u094B\u0903 \u092A\u0930\u093F\u0938\u094D\u092B\u0941\u0930\u0924\u093E \u0924\u0941\u0930\u094D\u092F\u0930\u0938\u0947\u0928 \u092E\u0927\u094D\u092F\u0926\u0936\u093E\u092E\u092A\u094D\u092F\u0935\u0937\u094D\u091F\u092E\u094D\u092D\u092F\u0941\u0915\u094D\u0924\u094D\u092F\u093E \u0935\u094D\u092F\u093E\u092A\u094D\u0928\u0941\u092F\u093E\u0926\u094D\u092F\u0947\u0928 \u0924\u0928\u094D\u092E\u092F\u0940\u092D\u093E\u0935\u092E\u093E\u092A\u094D\u0928\u0941\u092F\u093E\u0924\u094D\u0964 \u091C\u093E\u0917\u094D\u0930\u0924\u094D\u0938\u094D\u0935\u092A\u094D\u0928\u0938\u0941\u0937\u0941\u092A\u094D\u0924\u0947\u0937\u0941 \u0924\u0941\u0930\u094D\u092F\u093E\u092D\u094B\u0917\u0938\u092E\u094D\u092D\u0935\u0903 (\u0967-\u096D) \u0907\u0924\u094D\u092F\u0928\u0947\u0928\u094B\u0926\u094D\u092F\u092E\u0936\u0915\u094D\u0924\u093F\u091A\u0915\u094D\u0930\u093E\u0928\u0941\u0938\u0928\u094D\u0927\u094D\u092F\u0935\u0937\u094D\u091F\u092E\u094D\u092D\u092D\u093E\u091C\u0903 \u0938\u094D\u0935\u0930\u0938\u092A\u094D\u0930\u0938\u0930\u091C\u094D\u091C\u093E\u0917\u0930\u093E\u0926\u093F\u092A\u0926\u0947\u0937\u0941 \u0938\u0924\u094D\u0924\u093E\u092E\u093E\u0924\u094D\u0930\u0902 \u0924\u0941\u0930\u094D\u092F\u0938\u094D\u092F\u094B\u0915\u094D\u0924\u092E\u094D\u0964 \u0924\u094D\u0930\u093F\u0924\u092F\u092D\u094B\u0915\u094D\u0924\u093E \u0935\u0940\u0930\u0947\u0936\u0903 (\u0967-\u0967\u0967) \u0907\u0924\u093F \u0936\u093E\u092E\u094D\u092D\u0935\u094B\u092A\u093E\u092F\u093E\u0928\u0941\u0917\u0941\u0923\u0939\u0920\u092A\u093E\u0915\u092F\u0941\u0915\u094D\u0924\u094D\u092F\u093E \u091C\u093E\u0917\u0930\u093E\u0926\u093F\u0938\u0902\u0939\u093E\u0930\u094B \u0926\u0930\u094D\u0936\u093F\u0924\u0903\u0964 \u0905\u0928\u0947\u0928 \u0924\u0941 \u0938\u0942\u0924\u094D\u0930\u0947\u0923\u093E\u0923\u0935\u094B\u091A\u093F\u0924\u093E\u0935\u0937\u094D\u091F\u092E\u094D\u092D\u092F\u0941\u0915\u094D\u0924\u094D\u092F\u093E \u0926\u0932\u0915\u0932\u094D\u092A\u0902 \u091C\u093E\u0917\u0930\u093E\u0926\u093F\u0924\u094D\u0930\u092F\u0902 \u0924\u0941\u0930\u094D\u092F\u0930\u0938\u093E\u0938\u093F\u0915\u094D\u0924\u0902 \u0915\u093E\u0930\u094D\u092F\u092E\u093F\u0924\u094D\u092F\u0941\u0915\u094D\u0924\u092E\u093F\u0924\u093F \u0935\u093F\u0936\u0947\u0937\u0903\u0965\u0968\u0966\u0965</p></div><hr><div class="trans"><p>Yata evamata\u1E25 \u015Buddhavidy\u0101svar\u016Bpamuktayuktibhir\u0101s\u0101ditamapi yath\u0101 na na\u015Byati tath\u0101 sarvada\u015B\u0101su yogin\u0101 s\u0101vadh\u0101nena bhavitavyamity\u0101ha\u2014</p><blockquote><p><strong>Tri\u1E63u caturtha\u1E41 tailavad\u0101secyam||20||</strong></p></blockquote><p>Tri\u1E63u j\u0101gar\u0101di\u1E63u pade\u1E63u caturtha\u1E41 \u015Buddhavidy\u0101prak\u0101\u015Bar\u016Bpa\u1E41 tury\u0101nandaras\u0101tmaka\u1E41 dh\u0101ma tailavaditi yath\u0101 taila\u1E41 krame\u1E47\u0101dhikamadhika\u1E41 prasarad\u0101\u015Braya\u1E41 vy\u0101pnoti tath\u0101secyam| Tri\u1E63vapi pade\u1E63\u016Bnme\u1E63opa\u015B\u0101nty\u0101tmak\u0101dyantako\u1E6Dyo\u1E25 parisphurat\u0101 turyarasena madhyada\u015B\u0101mapyava\u1E63\u1E6Dambhayukty\u0101 vy\u0101pnuy\u0101dyena tanmay\u012Bbh\u0101vam\u0101pnuy\u0101t| J\u0101gratsvapnasu\u1E63upte\u1E63u tury\u0101bhogasambhava\u1E25 (1-7) ityanenodyama\u015Bakticakr\u0101nusandhyava\u1E63\u1E6Dambhabh\u0101ja\u1E25 svarasaprasarajj\u0101gar\u0101dipade\u1E63u satt\u0101m\u0101tra\u1E41 turyasyoktam| Tritayabhokt\u0101 v\u012Bre\u015Ba\u1E25 (1-11) iti \u015B\u0101mbhavop\u0101y\u0101nugu\u1E47aha\u1E6Dhap\u0101kayukty\u0101 j\u0101gar\u0101disa\u1E41h\u0101ro dar\u015Bita\u1E25| Anena tu s\u016Btre\u1E47\u0101\u1E47avocit\u0101va\u1E63\u1E6Dambhayukty\u0101 dalakalpa\u1E41 j\u0101gar\u0101ditraya\u1E41 turyaras\u0101sikta\u1E41 k\u0101ryamityuktamiti vi\u015Be\u1E63a\u1E25||20||</p></div><hr><p>\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 <em>(yatas)</em> [\u044D\u0442\u043E \u043E\u0431\u0441\u0442\u043E\u0438\u0442] \u0442\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(evam)</em> --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0434\u0430\u0436\u0435 \u0442\u043E\u0442, \u043A\u0442\u043E \u0434\u043E\u0441\u0442\u0438\u0433 \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u041F\u0440\u0438\u043D\u0446\u0438\u043F\u0430, \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0432\u0441\u0435 \u0435\u0449\u0435 \u043E\u0431\u043C\u0430\u043D\u0443\u0442 \u0442\u0430\u043A\u0438\u043C\u0438 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0430\u043C\u0438--, \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E <em>(atas)</em> Yog\u012B \u0434\u043E\u043B\u0436\u0435\u043D \u0431\u044B\u0442\u044C \u0432\u043D\u0438\u043C\u0430\u0442\u0435\u043B\u0435\u043D \u0438 \u043E\u0441\u0442\u043E\u0440\u043E\u0436\u0435\u043D <em>(tath\u0101... yogin\u0101 s\u0101vadh\u0101nena bhavitavyam)</em> \u043F\u0440\u0438 \u0432\u0441\u0435\u0445 \u043E\u0431\u0441\u0442\u043E\u044F\u0442\u0435\u043B\u044C\u0441\u0442\u0432\u0430\u0445 <em>(sarva-da\u015B\u0101su)</em>, \u0447\u0442\u043E\u0431\u044B <em>(yath\u0101)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0430\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(sva-r\u016Bpam)</em> \u0427\u0438\u0441\u0442\u043E\u0433\u043E \u0417\u043D\u0430\u043D\u0438\u044F <em>(\u015Buddha-vidy\u0101)</em>, \u043F\u0440\u0438\u043E\u0431\u0440\u0435\u0442\u0435\u043D\u043D\u043E\u0433\u043E [\u0438\u043C] <em>(\u0101s\u0101ditam api)</em>, \u043D\u0435 \u0438\u0441\u0447\u0435\u0437\u043B\u0430 <em>(na na\u015Byati)</em>. [\u015Aiva, \u0430\u0432\u0442\u043E\u0440 \u015Aivas\u016Btra-s,] \u0441\u043A\u0430\u0437\u0430\u043B \u0442\u0430\u043A <em>(iti \u0101ha)</em>\u2014</p><blockquote><p><strong>\u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F, [\u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u0435\u043C] <em>(caturtham)</em>, \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0432\u043B\u0438\u0432\u0430\u0442\u044C <em>(\u0101secyam)</em> \u043F\u043E\u0434\u043E\u0431\u043D\u043E <em>(vat)</em> [\u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E\u043C\u0443 \u043F\u043E\u0442\u043E\u043A\u0443] \u043C\u0430\u0441\u043B\u0430 <em>(taila)</em> \u0432 [\u0434\u0440\u0443\u0433\u0438\u0435] \u0442\u0440\u0438 <em>(tri\u1E63u)</em>, [\u0442.\u0435. \u0432 \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435, \u0441\u043E\u043D \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u0439 \u0441\u043E\u043D]||20||</strong></p></blockquote><p>[\u0422\u0435\u0440\u043C\u0438\u043D] tri\u1E63u <em>(tri\u1E63u)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u0432 [\u0434\u0440\u0443\u0433\u0438\u0435 \u0442\u0440\u0438] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(pade\u1E63u)</em> \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F \u0438 \u043F\u0440.<em>(j\u0101gar\u0101-\u0101di\u1E63u)</em>. [\u0421\u043B\u043E\u0432\u043E] caturtha --\u0442.\u0435. \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0435-- <em>(caturtham)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442] \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(dh\u0101ma)</em>, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0435 \u0438\u0437 <em>(\u0101tmakam)</em> \u044D\u043B\u0438\u043A\u0441\u0438\u0440\u0430 <em>(rasa)</em> \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 \u0422\u0443\u0440\u044C\u0438 --\u0442.\u0435. \u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u0430 \u0447\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F-- <em>(turya-\u0101nanda)</em>, \u0447\u044C\u0435\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u043E\u0439 <em>(r\u016Bpam)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0421\u0432\u0435\u0442 <em>(prak\u0101\u015Ba)</em> \u0427\u0438\u0441\u0442\u043E\u0433\u043E \u0417\u043D\u0430\u043D\u0438\u044F <em>(\u015Buddha-vidy\u0101)</em>. [\u0412\u044B\u0440\u0430\u0436\u0435\u043D\u0438\u0435] &quot;tailavat&quot; <em>(taila-vat iti)</em> [\u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442, \u0447\u0442\u043E] \u0442\u043E\u0447\u043D\u043E \u0442\u0430\u043A\u0436\u0435, \u043A\u0430\u043A <em>(yath\u0101)</em> [\u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u044B\u0439 \u043F\u043E\u0442\u043E\u043A] \u043C\u0430\u0441\u043B\u0430 <em>(tailam)</em>, \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u044F\u044F\u0441\u044C <em>(krame\u1E47a... prasarat)</em> \u0431\u043E\u043B\u044C\u0448\u0435 \u0438 \u0431\u043E\u043B\u044C\u0448\u0435 <em>(adhikam adhikam)</em>, \u0437\u0430\u043F\u043E\u043B\u043D\u044F\u0435\u0442 <em>(vy\u0101pnoti)</em> \u043F\u043E\u043B\u0443\u0447\u0430\u0442\u0435\u043B\u044F <em>(\u0101\u015Brayam)</em>, \u0442\u0430\u043A\u0436\u0435 <em>(tath\u0101)</em> \u0438 [\u0447\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F] \u0434\u043E\u043B\u0436\u043D\u043E \u0432\u043B\u0438\u0432\u0430\u0442\u044C\u0441\u044F <em>(\u0101secyam)</em> [\u0432 \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435, \u0441\u043E\u043D \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u0439 \u0441\u043E\u043D]|</p><p>\u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043C\u0435\u0442\u043E\u0434\u0430 <em>(yukty\u0101)</em> \u043D\u0435\u043F\u043E\u043A\u043E\u043B\u0435\u0431\u0438\u043C\u043E\u0433\u043E \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u043D\u0438\u044F --\u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0443\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0433\u043E \u0432\u043D\u0438\u043C\u0430\u043D\u0438\u044F \u043A \u0421\u0430\u043C\u043E\u0441\u0442\u0438, \u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0439\u0441\u044F \u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u0435\u043C-- <em>(ava\u1E63\u1E6Dambha)</em>, [Yog\u012B] \u0434\u043E\u043B\u0436\u0435\u043D \u0442\u0430\u043A\u0436\u0435 \u043F\u0440\u043E\u043F\u0438\u0442\u044B\u0432\u0430\u0442\u044C <em>(api... vy\u0101pnuy\u0101t)</em> \u043F\u0440\u043E\u043C\u0435\u0436\u0443\u0442\u043E\u0447\u043D\u043E\u0435 <em>(madhya)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(da\u015B\u0101m)</em> \u044D\u043B\u0438\u043A\u0441\u0438\u0440\u043E\u043C <em>(rasena)</em> \u0422\u0443\u0440\u044C\u0438 (Turya) --\u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F-- <em>(uktam)</em>, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(parisphurat\u0101)</em> \u043D\u0430 \u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u0439 \u0438 \u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0439 \u0442\u043E\u0447\u043A\u0430\u0445 <em>(\u0101di-anta-ko\u1E6Dyo\u1E25)</em> \u2014\u0433\u0434\u0435 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u0435 <em>(upa\u015B\u0101nti-\u0101tmaka)</em> unme\u1E63a --\u0442.\u0435. \u043E\u0442\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u044F \u0432\u0441\u0435\u043E\u0431\u044A\u0435\u043C\u043B\u044E\u0449\u0435\u0433\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F-- <em>(unme\u1E63a)</em>\u2014 \u0432\u043E \u0432\u0440\u0435\u043C\u044F \u0442\u0440\u0435\u0445 <em>(tri\u1E63u api)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 [\u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F, \u0441\u043D\u0430 \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430] <em>(pade\u1E63u)</em>. \u041F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u044D\u0442\u043E\u0433\u043E --\u0442.\u0435. \u0434\u0435\u043B\u0430\u044F \u0442\u0430\u043A-- <em>(yena)</em>, [\u0433\u0440\u0443\u043F\u043F\u0430 \u0442\u0440\u0435\u0445 \u043E\u0431\u044B\u0447\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F] \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 <em>(\u0101pnuy\u0101t)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(bh\u0101vam)</em> \u043E\u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u043B\u0435\u043D\u0438\u044F <em>(may\u012B)</em> \u0441 \u042D\u0442\u0438\u043C --\u0441 \u0422\u0443\u0440\u044C\u0435\u0439, \u0438\u043B\u0438 \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u044B\u043C \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C-- <em>(tad)</em><sup>1</sup>|</p><p>&quot;[\u0414\u0430\u0436\u0435] \u0432\u043E \u0432\u0440\u0435\u043C\u044F \u044D\u0442\u0438\u0445 \u0440\u0430\u0437\u043D\u044B\u0445 [\u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F] <em>(bhede)</em>, \u043A\u0430\u043A \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435 <em>(j\u0101grat)</em>, \u0441\u043E\u043D \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 <em>(svapna)</em> \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u0439 \u0441\u043E\u043D <em>(su\u1E63upta)</em>, \u0438\u043C\u0435\u044E\u0442 \u043C\u0435\u0441\u0442\u043E <em>(sambhava\u1E25)</em> \u0432\u043E\u0441\u0442\u043E\u0440\u0433 \u0438 \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435 <em>(\u0101bhoga)</em> \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(turya)</em>. (I, 7) [\u0434\u0430\u043D\u043D\u043E\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F] <em>(1-7 iti)</em>&quot;. \u042D\u0442\u0438\u043C [\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u043E\u043C] <em>(anena)</em>, \u0431\u044B\u043B\u043E \u043F\u0440\u043E\u0432\u043E\u0437\u0433\u043B\u0430\u0448\u0435\u043D\u043E <em>(uktam)</em> \u0442\u043E\u043B\u044C\u043A\u043E <em>(m\u0101tra)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435 <em>(satt\u0101)</em> \u0422\u0443\u0440\u044C\u0438 <em>(turyasya)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0440\u0430\u0441\u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u044F\u0435\u0442 <em>(prasarat)</em> \u0441\u0432\u043E\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 <em>(sva)</em> \u044D\u043B\u0438\u043A\u0441\u0438\u0440 <em>(rasa)</em> \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(pade\u1E63u)</em> \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(j\u0101gar\u0101)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em>, [\u0432 \u0441\u043B\u0443\u0447\u0430\u0435] \u0442\u043E\u0433\u043E, \u043A\u0442\u043E \u043F\u0440\u0435\u0434\u0430\u043D <em>(bh\u0101ja\u1E25)</em> \u043D\u0435\u043F\u043E\u043A\u043E\u043B\u0435\u0431\u0438\u043C\u043E\u043C\u0443 \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u043D\u0438\u044E <em>(ava\u1E63\u1E6Dambha)</em> \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E\u0433\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(anusandhi)</em> \u0433\u0440\u0443\u043F\u043F\u044B <em>(cakra)</em> \u0441\u0438\u043B <em>(\u015Bakti)</em> [\u0438\u043B\u0438 \u043F\u0440\u043E\u0449\u0435 \u0433\u043E\u0432\u043E\u0440\u044F, \u0442\u043E\u0433\u043E, \u0432 \u043A\u043E\u043C \u0438\u043C\u0435\u0435\u0442\u0441\u044F] udyama, \u0438\u043B\u0438 \u0441\u043F\u043E\u043D\u0442\u0430\u043D\u043D\u043E\u0435 \u0432\u043E\u0437\u043D\u0438\u043A\u043D\u043E\u0432\u0435\u043D\u0438\u044F [\u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F] <em>(udyama)</em>|</p><p>&quot;\u041E\u043D \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u0435\u043C <em>(\u012B\u015Ba\u1E25)</em> [\u0441\u0432\u043E\u0438\u0445] \u0447\u0443\u0432\u0441\u0442\u0432 <em>(v\u012Bra)</em>, \u0442\u0435\u043C, \u043A\u0442\u043E \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0430\u0435\u0442\u0441\u044F [\u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u043C &quot;\u0101bhoga&quot;, \u0438\u043B\u0438 \u0431\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0432\u043E\u0441\u0442\u043E\u0440\u0433\u043E\u043C] <em>(bhokt\u0101)</em> \u0432 \u0442\u0440\u0438\u0430\u0434\u0435 [\u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F, \u0441\u043D\u0430 \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430] <em>(tritaya)</em>. (I, 11) [\u0434\u0430\u043D\u043D\u043E\u0433\u043E \u041F\u0438\u0441\u0430\u043D\u0438\u044F] <em>(1-11 iti)</em>&quot;. [\u0412 \u044D\u0442\u043E\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435,] \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(sa\u1E41h\u0101ra\u1E25)</em> \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(j\u0101gar\u0101)</em>, \u0438 \u043F\u0440. <em>(\u0101di)</em> \u0431\u044B\u043B\u043E \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u043E <em>(dar\u015Bita\u1E25)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043C\u0435\u0442\u043E\u0434\u0430 <em>(yukty\u0101)</em> ha\u1E6Dhap\u0101ka --\u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E, \u0430\u0441\u0441\u0438\u043C\u0438\u043B\u044F\u0446\u0438\u0435\u0439 \u0441\u0438\u043B\u044B \u0438 \u0443\u043F\u043E\u0440\u0441\u0442\u0432\u0430-- <em>(ha\u1E6Dha-p\u0101ka)</em> \u0432 \u0441\u043E\u043E\u0442\u0432\u0435\u0442\u0441\u0442\u0432\u0438\u0438 \u0441 <em>(anugu\u1E47a)</em> \u015A\u0101mbhavop\u0101ya --\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430\u043C\u0438, \u0438\u043B\u0438 \u043C\u0435\u0442\u043E\u0434\u0430\u043C\u0438, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0438\u043C\u0438\u0441\u044F \u043A \u015Aiva-- <em>(\u015B\u0101mbhava-up\u0101ya)</em><sup>2</sup></p><p>. \u041E\u0434\u043D\u0430\u043A\u043E <em>(tu)</em>, \u0432 \u044D\u0442\u043E\u043C <em>(anena)</em> \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435 --\u0442.\u0435. \u0432 \u0440\u0430\u0441\u0441\u043C\u0430\u0442\u0440\u0438\u0432\u0430\u0435\u043C\u043E\u043C-- <em>(s\u016Btre\u1E47a)</em> \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F, \u0447\u0442\u043E <em>(iti uktam)</em> \u0442\u0440\u0438\u0430\u0434\u0430 <em>(trayam)</em> \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435 <em>(j\u0101gar\u0101)</em>, \u0438 \u043F\u0440. <em>(\u0101di)</em>, \u043F\u043E\u0434\u043E\u0431\u043D\u0430\u044F <em>(kalpam)</em> \u043D\u043E\u0436\u043D\u0430\u043C \u043C\u0435\u0447\u0430 <em>(dala)</em><sup>3</sup>, \u0434\u043E\u043B\u0436\u043D\u0430 \u0431\u044B\u0442\u044C \u043F\u0440\u043E\u043F\u0438\u0442\u0430\u043D\u0430 <em>(\u0101siktam k\u0101ryam)</em> \u044D\u043B\u0438\u043A\u0441\u0438\u0440\u043E\u043C <em>(rasa)</em> \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F <em>(turya)</em> \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043C\u0435\u0442\u043E\u0434\u0430 <em>(yukty\u0101)</em> [\u0432\u044B\u0448\u0435\u0443\u043A\u0430\u0437\u0430\u043D\u043D\u043E\u0433\u043E] \u043D\u0435\u043F\u043E\u043A\u043E\u043B\u0435\u0431\u0438\u043C\u043E\u0433\u043E \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u043D\u0438\u044F <em>(ava\u1E63\u1E6Dambha)</em>, \u0441\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E <em>(ucita)</em> \u0100\u1E47avop\u0101ya --\u0441\u0440\u0435\u0434\u0441\u0442\u0432, \u0438\u043B\u0438 \u043C\u0435\u0442\u043E\u0434\u043E\u0432, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0438\u0445\u0441\u044F \u043A a\u1E47u, \u0438\u043B\u0438 \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0439 \u043B\u0438\u0447\u043D\u043E\u0441\u0442\u0438-- <em>(\u0101\u1E47ava)</em>. \u0412 \u044D\u0442\u043E\u043C \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u0435 <em>(iti vi\u015Be\u1E63a\u1E25)</em> [\u043C\u0435\u0436\u0434\u0443 \u044D\u0442\u0438\u043C\u0438 \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430\u043C\u0438, \u0442.\u0435. \u043C\u0435\u0436\u0434\u0443 I, 7, I, 11 \u0438 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0438\u043C --III, 20--]||20||</p><hr><ol><li>\u0427\u0442\u043E\u0431\u044B \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043F\u043E\u043D\u044F\u0442\u044C, \u0447\u0442\u043E \u043C\u0443\u0434\u0440\u0435\u0446 \u0445\u043E\u0442\u0435\u043B \u0432\u044B\u0440\u0430\u0437\u0438\u0442\u044C \u0432 \u044D\u0442\u043E\u043C \u0430\u0431\u0437\u0430\u0446\u0435, \u0432\u0430\u043C \u043D\u0430\u0434\u043E \u0431\u044B\u0442\u044C Yog\u012B, \u0445\u043E\u0440\u043E\u0448\u043E \u0437\u043D\u0430\u043A\u043E\u043C\u044B\u043C \u0441 \u044D\u0442\u0438\u043C\u0438 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u0430\u043C\u0438. \u0412 \u043B\u044E\u0431\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, \u0435\u0441\u043B\u0438 \u0432\u044B \u0435\u0449\u0435 \u043D\u0435 \u044F\u0432\u043B\u044F\u0435\u0442\u0435\u0441\u044C Yog\u012B, \u0432\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u043F\u043E\u043F\u044B\u0442\u0430\u0442\u044C\u0441\u044F \u043F\u043E\u043D\u044F\u0442\u044C \u044D\u0442\u043E \u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442\u0443\u0430\u043B\u044C\u043D\u043E. \u0421\u043B\u0443\u0448\u0430\u0439\u0442\u0435: \u0411\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u043B\u044E\u0434\u0435\u0439 \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u044E\u0442 \u0441\u0432\u043E\u0435 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u0412\u044B\u0441\u0448\u0435\u0435 \u042F \u0442\u043E\u043B\u044C\u043A\u043E \u0432 \u043D\u0430\u0447\u0430\u043B\u0435 \u0438 \u0432 \u043A\u043E\u043D\u0446\u0435 \u0442\u0440\u0435\u0445 \u043E\u0431\u044B\u0447\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F (\u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F, \u0441\u043D\u0430 \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430). \u041A\u043E\u043D\u0435\u0447\u043D\u043E, \u043D\u0430 \u043D\u0430\u0447\u0430\u043B\u044C\u043D\u043E\u043C \u044D\u0442\u0430\u043F\u0435 \u0441\u0432\u043E\u0435\u0439 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0438 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u2014 \u0442\u0430\u043A\u043E\u0439 \u0436\u0435 \u043A\u0430\u043A \u0438 \u0432\u0441\u0435 \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0435. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u0435\u0433\u043E \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u0435 \u0421\u0430\u043C\u043E\u0441\u0442\u0438, \u043A\u0430\u043A \u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u044F, \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E \u0442\u043E\u043B\u044C\u043A\u043E \u0432 \u043D\u0430\u0447\u0430\u043B\u044C\u043D\u044B\u0445 \u0438 \u043A\u043E\u043D\u0435\u0447\u043D\u044B\u0445 \u0442\u043E\u0447\u043A\u0430\u0445 \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439. \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u043C \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0435\u0433\u043E \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u042F, \u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E \u043A\u0430\u043A Turya, \u0438\u043B\u0438 \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u043E \u043E\u0442\u043B\u0438\u0447\u0430\u0435\u0442\u0441\u044F \u043E\u0442 \u0442\u0440\u0435\u0445 \u0434\u0440\u0443\u0433\u0438\u0445. \u041A\u043E\u0433\u0434\u0430 \u043E\u0431\u044B\u0447\u043D\u043E\u0435 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F (\u0431\u0443\u0434\u044C \u0442\u043E \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435, \u0441\u043E\u043D \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438\u043B\u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u0439 \u0441\u043E\u043D) \u043D\u0430\u0447\u0438\u043D\u0430\u0435\u0442\u0441\u044F \u0438\u043B\u0438 \u0437\u0430\u043A\u0430\u043D\u0447\u0438\u0432\u0430\u0435\u0442\u0441\u044F, \u0432 \u044D\u0442\u043E\u0442 \u043C\u043E\u043C\u0435\u043D\u0442 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u0435 \u0443\u043D\u043C\u0435\u0448\u0438 (unme\u1E63a), \u0438\u043B\u0438 \u043E\u0442\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u044F \u0432\u0441\u0435\u043E\u0431\u044A\u0435\u043C\u043B\u044E\u0449\u0435\u0433\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F. \u041F\u043E\u0434 unme\u1E63a \u043F\u043E\u0434\u0440\u0430\u0437\u0443\u043C\u0435\u0432\u0430\u0435\u0442\u0441\u044F \u043B\u044E\u0431\u043E\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F\u0445 \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0434\u0435\u0440\u0435\u0432\u043E), \u0441\u043D\u0430 \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u0441\u0442\u0440\u0430\u043D\u043D\u044B\u0435 \u0446\u0432\u0435\u0442\u0430) \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430 (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u043F\u0443\u0441\u0442\u043E\u0442\u0430). Unme\u1E63a \u043F\u0440\u0438\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u0442\u043E\u043B\u044C\u043A\u043E &quot;\u043F\u043E\u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435&quot; \u043E\u0431\u044B\u0447\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F. \u0412 \u0438\u0445 \u043D\u0430\u0447\u0430\u043B\u0435 \u0438 \u0432 \u043A\u043E\u043D\u0446\u0435 unme\u1E63a \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442.</li></ol><p>\u0421 \u0434\u0440\u0443\u0433\u043E\u0439 \u0441\u0442\u043E\u0440\u043E\u043D\u044B, Turya, \u0438\u043B\u0438 \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0435 \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u043D\u0438\u043A\u043E\u0433\u0434\u0430 \u043D\u0435 \u043E\u0442\u0445\u043E\u0434\u0438\u0442 \u043E\u0442 \u0441\u0432\u043E\u0435\u0439 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u043F\u0440\u0438\u0440\u043E\u0434\u044B, \u0442.\u043A. \u0434\u043B\u0438\u0442\u0441\u044F \u0432\u0435\u0447\u043D\u043E. \u042D\u0442\u043E \u043D\u0435 \u043F\u043E\u0445\u043E\u0436\u0435 \u043D\u0430 \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0435 \u0442\u0440\u0438 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u043F\u0440\u0435\u0445\u043E\u0434\u044F\u0449\u0438\u043C\u0438. Turya \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043E\u0447\u0435\u0432\u0438\u0434\u043D\u043E\u0439 \u0434\u043B\u044F \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u0430 \u043B\u044E\u0434\u0435\u0439, \u0442\u043E\u043B\u044C\u043A\u043E \u043A\u043E\u0433\u0434\u0430 unme\u1E63a \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442, \u043D\u043E \u043A\u043E\u0433\u0434\u0430 \u043E\u043D\u0430 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F, \u044D\u0442\u0438 \u043B\u044E\u0434\u0438 \u0431\u043E\u043B\u044C\u0448\u0435 \u043D\u0435 \u043E\u0441\u043E\u0437\u043D\u0430\u044E\u0442 \u0441\u0432\u043E\u0435 \u0412\u044B\u0441\u0448\u0435\u0435 \u042F. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 Yog\u012B \u043F\u0440\u043E\u0434\u0432\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0432 \u0441\u0432\u043E\u0435\u0439 \u043F\u0440\u0430\u043A\u0442\u0438\u043A\u0435, \u043E\u0434\u043D\u0430\u0436\u0434\u044B \u043F\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0427\u0438\u0441\u0442\u043E\u0435 \u0417\u043D\u0430\u043D\u0438\u0435 (\u015Auddhavidy\u0101), \u0438 \u043E\u043D \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u043E\u0441\u043E\u0437\u043D\u0430\u0435\u0442 \u0441\u0432\u043E\u044E \u0421\u0430\u043C\u043E\u0441\u0442\u044C, \u043A\u0430\u043A \u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u044F \u0432\u0441\u0435\u0445 \u0441\u0432\u043E\u0438\u0445 \u043F\u0435\u0440\u0435\u0436\u0438\u0432\u0430\u043D\u0438\u0439, \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u0445 \u0441 \u043D\u0438\u043C \u0432 \u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0438, \u0432\u043E \u0441\u043D\u0435 \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u043C \u0441\u043D\u0435. \u042D\u0442\u043E \u0437\u043D\u0430\u043C\u0435\u043D\u0443\u0435\u0442 \u0441\u043E\u0431\u043E\u0439 \u0435\u0433\u043E \u0434\u043E\u0441\u0442\u0438\u0436\u0435\u043D\u0438\u0435 \u0422\u0443\u0440\u044C\u0438. \u0421 \u044D\u0442\u043E\u0433\u043E \u043C\u043E\u043C\u0435\u043D\u0442\u0430 \u0435\u043C\u0443 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0437\u0430\u0441\u0442\u0430\u0432\u0438\u0442\u044C Turya \u043F\u043E\u0441\u0442\u0435\u043F\u0435\u043D\u043D\u043E \u043F\u0440\u043E\u043F\u0438\u0442\u044B\u0432\u0430\u0442\u044C \u043E\u0441\u0442\u0430\u043B\u044C\u043D\u044B\u0435 \u0442\u0440\u0438 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u043D\u0435\u043F\u0440\u0435\u0440\u044B\u0432\u043D\u043E\u043C\u0443 \u043F\u043E\u0442\u043E\u043A\u0443 \u043C\u0430\u0441\u043B\u0430, \u043D\u0430\u043F\u043E\u043B\u043D\u044F\u044E\u0449\u0435\u043C\u0443 \u043F\u043E\u043B\u0443\u0447\u0430\u0442\u0435\u043B\u044F. \u0412 \u043A\u043E\u043D\u0446\u0435 \u043A\u043E\u043D\u0446\u043E\u0432, \u0432\u0441\u0435 \u044D\u0442\u0438 \u0442\u0440\u0438 \u043E\u0431\u044B\u0447\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F (\u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u0435, \u0441\u043E\u043D \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438 \u0438 \u0433\u043B\u0443\u0431\u043E\u043A\u0438\u0439 \u0441\u043E\u043D) \u0441\u0442\u0430\u043D\u0443\u0442 \u0442\u043E\u0436\u0434\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B \u0441 Turya \u0438 \u043E\u0441\u0442\u0430\u043D\u0435\u0442\u0441\u044F \u0442\u043E\u043B\u044C\u043A\u043E &quot;\u043E\u0434\u043D\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435&quot;, \u0442.\u0435. Yog\u012B \u0431\u0443\u0434\u0435\u0442 \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0443\u0441\u0442\u0430\u043D\u043E\u0432\u043B\u0435\u043D \u0432 \u0441\u0432\u043E\u0435\u043C \u0412\u044B\u0441\u0448\u0435\u043C \u042F \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E. \u041D\u0430 \u0441\u0430\u043C\u043E\u043C \u0434\u0435\u043B\u0435, \u0442\u043E\u043B\u044C\u043A\u043E \u044D\u0442\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0438 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443\u0435\u0442 \u0432\u0435\u0447\u043D\u043E. \u0414\u0440\u0443\u0433\u0438\u0435 \u0442\u0440\u0438 \u2014 \u044D\u0442\u043E \u043F\u0440\u043E\u0441\u0442\u043E \u0431\u043B\u0430\u0436\u0435\u043D\u043D\u0430\u044F \u0438\u0433\u0440\u0430 \u015Aakti. \u041E\u043D\u0438 \u0432\u043E\u0437\u043D\u0438\u043A\u0430\u044E\u0442, \u043A\u043E\u0433\u0434\u0430 \u041E\u043D\u0430 (\u043F\u043E \u0432\u0441\u0435\u0439 \u0432\u0438\u0434\u0438\u043C\u043E\u0441\u0442\u0438) \u043C\u0430\u0441\u043A\u0438\u0440\u0443\u0435\u0442 Turya \u0438 \u044D\u043A\u0441\u043F\u043E\u043D\u0438\u0440\u0443\u0435\u0442 unme\u1E63a, \u0438\u043B\u0438 \u043E\u0442\u043E\u0431\u0440\u0430\u0436\u0435\u043D\u0438\u0435 \u0432\u0441\u0435\u043E\u0431\u044A\u0435\u043C\u043B\u044E\u0449\u0435\u0433\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F. \u041F\u043E\u043C\u0438\u043C\u043E \u043C\u043E\u0438\u0445 \u043E\u0431\u044A\u044F\u0441\u043D\u0435\u043D\u0438\u0439, \u0432\u0441\u0435 \u044D\u0442\u043E \u2014 \u0432\u043E\u043F\u0440\u043E\u0441 \u043B\u0438\u0447\u043D\u043E\u0433\u043E \u043E\u043F\u044B\u0442\u0430. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0435\u0441\u044C \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0438\u043C Yog\u012B \u0438 \u0438\u0441\u043F\u044B\u0442\u0430\u0439\u0442\u0435 \u0432\u0430\u0448\u0443 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E \u0431\u0435\u0437\u0433\u0440\u0430\u043D\u0438\u0447\u043D\u043E\u0441\u0442\u044C. OK, \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E.</p><ol start="2"><li><p>\u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u043E\u0442 \u0430\u0444\u043E\u0440\u0438\u0437\u043C (I, 11) \u2014 \u0438\u0437 \u043F\u0435\u0440\u0432\u043E\u0439 \u0433\u043B\u0430\u0432\u044B, \u043E\u0442\u043D\u043E\u0441\u044F\u0449\u0435\u0439\u0441\u044F \u043A \u015A\u0101mbhavop\u0101ya, \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 \u043E\u0431\u044B\u0447\u043D\u044B\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F (\u0431\u043E\u0434\u0440\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F, \u0441\u043D\u0430 \u0441\u043E \u0441\u043D\u043E\u0432\u0438\u0434\u0435\u043D\u0438\u044F\u043C\u0438, \u0433\u043B\u0443\u0431\u043E\u043A\u043E\u0433\u043E \u0441\u043D\u0430) \u043F\u043E\u043A\u0430\u0437\u0430\u043D\u043E \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043C\u0435\u0442\u043E\u0434\u0430 ha\u1E6Dhap\u0101ka, \u0438\u043B\u0438 \u0430\u0441\u0441\u0438\u043C\u0438\u043B\u044F\u0446\u0438\u0438 \u043E\u043F\u044B\u0442\u0430 \u0441\u0438\u043B\u043E\u0439 \u0438 \u043D\u0430\u0441\u0442\u043E\u0439\u0447\u0438\u0432\u043E\u0441\u0442\u044C\u044E, (\u0432\u044B\u0440\u0430\u0436\u0430\u044F\u0441\u044C \u0444\u0438\u0433\u0443\u0440\u0430\u043B\u044C\u043D\u043E), &quot;\u043E\u0434\u043D\u0438\u043C \u043C\u0430\u0445\u043E\u043C&quot;. \u042D\u0442\u043E\u0442 \u043C\u0435\u0442\u043E\u0434 \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043A kram\u0101tikrama, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D \u0432\u044B\u0445\u043E\u0434\u0438\u0442 \u0437\u0430 \u0440\u0430\u043C\u043A\u0438 krama, \u0438\u043B\u0438 \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438, \u0442.\u043A. Yog\u012B \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0437\u0430 \u043E\u0434\u0438\u043D \u0448\u0430\u0433. \u041A\u043E\u043D\u0435\u0447\u043D\u043E, \u044D\u0442\u043E \u0442\u0440\u0435\u0431\u0443\u0435\u0442 \u043D\u0435\u0432\u0435\u0440\u043E\u044F\u0442\u043D\u043E\u0439 \u0434\u0443\u0445\u043E\u0432\u043D\u043E\u0439 \u0441\u0438\u043B\u044B, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043E\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442 \u0443 \u043F\u043E\u0434\u0430\u0432\u043B\u044F\u044E\u0449\u0435\u0433\u043E \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u0430 \u0443\u0447\u0435\u043D\u0438\u043A\u043E\u0432. \u0411\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u043B\u044E\u0434\u0435\u0439 \u043D\u0430\u0447\u0438\u043D\u0430\u044E\u0442 \u0441\u0432\u043E\u0439 \u0434\u0443\u0445\u043E\u0432\u043D\u044B\u0439 \u043F\u0443\u0442\u044C \u0441 \u0100\u1E47avop\u0101ya \u0438 \u0441\u043E \u0432\u0440\u0435\u043C\u0435\u043D\u0435\u043C \u043E\u043D\u0438 \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0443\u0442 \u015A\u0101ktop\u0101ya \u0438 \u015A\u0101mbhavop\u0101ya (\u043E\u0431\u044B\u0447\u043D\u043E \u044D\u0442\u043E \u0437\u0430\u043D\u0438\u043C\u0430\u0435\u0442 \u043C\u043D\u043E\u0433\u043E \u043B\u0435\u0442, \u0434\u0435\u0441\u044F\u0442\u0438\u043B\u0435\u0442\u0438\u0439 \u0438\u043B\u0438 \u0434\u0430\u0436\u0435 \u0432\u0441\u044E \u0436\u0438\u0437\u043D\u044C). \u0422\u043E\u043B\u044C\u043A\u043E \u0435\u0434\u0438\u043D\u0438\u0446\u044B \u043D\u0430\u0447\u043D\u0443\u0442 \u0441 \u015A\u0101ktop\u0101ya, \u0438 \u0442\u043E\u043B\u044C\u043A\u043E \u0441\u0430\u043C\u044B\u0435 \u0434\u043E\u0441\u0442\u043E\u0439\u043D\u044B\u0435 \u043D\u0430\u0447\u043D\u0443\u0442 \u0441\u0432\u043E\u0435 \u0434\u0443\u0445\u043E\u0432\u043D\u043E\u0435 \u043F\u0443\u0442\u0435\u0448\u0435\u0441\u0442\u0432\u0438\u0435 \u0441 \u015A\u0101mbhavop\u0101ya. \u041E\u0447\u0435\u0432\u0438\u0434\u043D\u043E, \u0447\u0435\u043C \u043C\u0435\u043D\u0435\u0435 \u0434\u043E\u0441\u0442\u043E\u0435\u043D \u0443\u0447\u0435\u043D\u0438\u043A, \u0442\u0435\u043C \u0441 \u0431\u043E\u043B\u0435\u0435 \u0432\u044B\u0441\u043E\u043A\u043E\u0439 up\u0101ya (\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u0430, \u0438\u043B\u0438 \u043C\u0435\u0442\u043E\u0434\u0430) \u043E\u043D \u0445\u043E\u0447\u0435\u0442 \u043D\u0430\u0447\u0430\u0442\u044C, \u0445\u0430-\u0445\u0430! \u0412 \u0446\u0435\u043B\u043E\u043C, \u044D\u0442\u043E \u043E\u0431\u044B\u0447\u043D\u0430\u044F \u043F\u0440\u043E\u0431\u043B\u0435\u043C\u0430 \u0441 \u043B\u044E\u0434\u044C\u043C\u0438: \u043E\u043D\u0438 \u043F\u0435\u0440\u0435\u043E\u0446\u0435\u043D\u0438\u0432\u0430\u044E\u0442 \u0441\u0432\u043E\u0438 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0435 \u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u0438, \u0438\u043C\u0435\u044F \u0434\u0435\u043B\u043E \u0441 \u0434\u0443\u0445\u043E\u0432\u043D\u044B\u043C\u0438 \u0432\u043E\u043F\u0440\u043E\u0441\u0430\u043C\u0438. \u0412 \u043A\u043B\u0430\u0441\u0441\u0435 \u043F\u043E \u043A\u0432\u0430\u043D\u0442\u043E\u0432\u043E\u0439 \u0444\u0438\u0437\u0438\u043A\u0435 \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u0438\u0437 \u043D\u0438\u0445 \u043D\u0430\u0432\u0435\u0440\u043D\u044F\u043A\u0430 \u0431\u0443\u0434\u0443\u0442 \u043E\u0441\u0442\u0430\u0432\u0430\u0442\u044C\u0441\u044F \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u0431\u0435\u0437\u043C\u043E\u043B\u0432\u043D\u044B\u043C\u0438, \u043D\u043E \u0432 \u043A\u043B\u0430\u0441\u0441\u0435 \u0419\u043E\u0433\u0438 \u043E\u043D\u0438 \u0432\u0441\u0435 \u0432\u0440\u0435\u043C\u044F \u0432\u044B\u0441\u043A\u0430\u0437\u044B\u0432\u0430\u044E\u0442 \u0441\u0432\u043E\u0435 \u043C\u043D\u0435\u043D\u0438\u0435 \u043F\u043E\u0447\u0442\u0438 \u043E\u0431\u043E \u0432\u0441\u0435\u043C. \u041F\u043E\u0447\u0435\u043C\u0443? \u0418\u0437-\u0437\u0430 \u0438\u0445 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0433\u043E \u043D\u0435\u0432\u0435\u0436\u0435\u0441\u0442\u0432\u0430, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0433\u043E\u0441\u044F \u0432 \u0432\u0438\u0434\u0435 \u0432\u044B\u0441\u043E\u043A\u043E\u043C\u0435\u0440\u0438\u044F. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0419\u043E\u0433\u0430 \u2014 \u043E\u0447\u0435\u043D\u044C \u0441\u043B\u043E\u0436\u043D\u0430\u044F/\u0433\u043B\u0443\u0431\u043E\u043A\u0430\u044F \u043D\u0430\u0443\u043A\u0430, \u0442\u043E\u043B\u044C\u043A\u043E \u044D\u043A\u0441\u043F\u0435\u0440\u0442\u044B \u0419\u043E\u0433\u0438 \u0438 \u0443\u0447\u0435\u043D\u044B\u0435 \u043C\u043E\u0433\u0443\u0442 \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u044C \u0447\u0442\u043E-\u0442\u043E, \u0447\u0442\u043E \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0441\u0442\u043E\u0438\u0442 \u0443\u0441\u043B\u044B\u0448\u0430\u0442\u044C.</p></li><li><p>\u0417\u0434\u0435\u0441\u044C \u0442\u0435\u0440\u043C\u0438\u043D &quot;dala&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0916\u0921\u094D\u0917\u0915\u094B\u0936&quot; - &quot;kha\u1E0Dgako\u015Ba&quot;, \u0438\u043B\u0438 \u043D\u043E\u0436\u043D\u044B \u043C\u0435\u0447\u0430. \u041F\u043E\u0434\u043E\u0431\u043D\u043E \u0442\u043E\u043C\u0443, \u043A\u0430\u043A \u043D\u043E\u0436\u043D\u044B \u043C\u0435\u0447\u0430 \u043E\u0442\u043B\u0438\u0447\u0430\u044E\u0442\u0441\u044F \u043E\u0442 \u043C\u0435\u0447\u0430, \u043D\u043E \u043E\u043D\u0438 \u043C\u043E\u0433\u0443\u0442 \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044C \u0435\u0433\u043E, \u0442\u043E\u0447\u043D\u043E \u0442\u0430\u043A\u0436\u0435 \u0442\u0440\u0438 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F \u043E\u0442\u043B\u0438\u0447\u0430\u044E\u0442\u0441\u044F \u043E\u0442 Turya (\u0427\u0435\u0442\u0432\u0435\u0440\u0442\u043E\u0433\u043E \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F), \u043D\u043E \u043E\u043D\u0438 \u043C\u043E\u0433\u0443\u0442 \u0443\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0442\u044C \u0438 \u043D\u0430\u043F\u043E\u043B\u043D\u044F\u0442\u044C\u0441\u044F \u0438\u043C.</p></li></ol></div>',1),i=[u];function s(p,o,y,d,h,n){return e(),m("div",null,i)}var l=a(r,[["render",s]]);export{k as __pageData,l as default};
